                "url": "https://bebbo.app/sites/default/files/styles/content_1200xh_/public/2021-10/2011-samir-karahoda-babies-3.webp?itok=s06ExZ_u",
                "name": "2011 - Samir Karahoda - Babies (3).jpg",
